// Host is the resolver for the worktree.host field. Reads obj.Host (set by toGraphQLWorktree); defensively falls back to "local" when empty so the v1 sentinel lives in one place.
func (r *worktreeResolver) Host(ctx context.Context, obj *graphql1.Worktree) (string, error) {
	if obj.Host == "" {
		return "local", nil
	}
	return obj.Host, nil
}

// Repo is the resolver for the worktree.repo field. Derives owner/repo from the worktree's origin remote URL; returns nil when origin is absent or not a GitHub URL.
func (r *worktreeResolver) Repo(ctx context.Context, obj *graphql1.Worktree) (*string, error) {
	if obj == nil || obj.Path == "" {
		return nil, nil
	}
	url, err := gh.ReadOriginURL(obj.Path)
	if err != nil {
		return nil, nil
	}
	owner, name, ok := gh.ParseGitHubURL(url)
	if !ok {
		return nil, nil
	}
	slug := owner + "/" + name
	return &slug, nil
}

// Pr is the resolver for the worktree.pr field. Looks up a PR whose headRef matches the worktree's branch via the PullRequestsForRepo DataLoader (which fetches PRs in all states per issue #489 so the TUI stale-fade UX works post-merge). Selection precedence: an OPEN match wins; otherwise the most-recent CLOSED/MERGED match. Returns nil for missing obj, empty branch, default branch, non-GitHub origin, or no headRef match in any state.
func (r *worktreeResolver) Pr(ctx context.Context, obj *graphql1.Worktree) (*graphql1.PullRequest, error) {
	if obj == nil || obj.Branch == "" {
		return nil, nil
	}
	// Default-branch exclusion: the default branch never has its own PR
	// targeting itself, so skip the DataLoader call entirely.
	if defaultBranch, ok := readDefaultBranch(obj.Path); ok && defaultBranch == obj.Branch {
		return nil, nil
	}
	// Derive the repo slug from the worktree's origin remote.
	url, err := gh.ReadOriginURL(obj.Path)
	if err != nil {
		return nil, nil // missing origin → null (graceful)
	}
	owner, name, ok := gh.ParseGitHubURL(url)
	if !ok {
		return nil, nil // non-GitHub origin → null
	}
	// Load all PRs (across all states) for the repo via the DataLoader.
	ldrs := loaders.FromContext(ctx)
	if ldrs == nil {
		return nil, fmt.Errorf("loaders not in context")
	}
	prs, err := ldrs.PullRequestsForRepo.Load(ctx, loaders.RepoKey{Owner: owner, Name: name})()
	if err != nil {
		return nil, err
	}
	// First pass: prefer any OPEN PR — the list is already sorted UpdatedAt
	// DESC by the GitHub API, so the first match is most-recent. Track the
	// first non-OPEN match as a fallback for the post-merge stale-fade case.
	var fallback *graphql1.PullRequest
	for _, pr := range prs {
		if pr == nil || pr.HeadRef != obj.Branch {
			continue
		}
		if pr.State == graphql1.PullRequestStateOpen {
			return pr, nil
		}
		if fallback == nil {
			fallback = pr
		}
	}
	return fallback, nil
}

// Issue is the resolver for the worktree.issue field. Parses the issue number from the worktree branch (rules ported from crates/orchard/src/github.rs) then fetches via the gh provider. Returns nil for empty branch, unparseable branch, missing/non-GitHub origin, unwired gh provider, or 404.
func (r *worktreeResolver) Issue(ctx context.Context, obj *graphql1.Worktree) (*graphql1.Issue, error) {
	if obj == nil || obj.Branch == "" {
		return nil, nil
	}

	n, ok := gh.ExtractIssueNumber(obj.Branch)
	if !ok {
		return nil, nil
	}

	url, err := gh.ReadOriginURL(obj.Path)
	if err != nil {
		return nil, nil
	}
	owner, name, ok := gh.ParseGitHubURL(url)
	if !ok {
		return nil, nil
	}

	if r.GH == nil {
		return nil, errGHNotConfigured
	}

	issue, err := r.GH.GetIssue(ctx, gh.IssueKey{Owner: owner, Name: name, Number: n})
	if err != nil {
		if gh.IsNotFound(err) {
			return nil, nil
		}
		return nil, err
	}
	return toGraphQLIssue(issue), nil
}

// Processes is the resolver for the worktree.processes field.
